#![cfg(test)]

use super::*;

#[test]
fn betti_checkerboard_two_cells() {
    // 2x2 high-low pattern — two disjoint high components at 0.6 threshold fraction of max.
    let w = 4_usize;
    let h = 4_usize;
    let mut p = vec![0.0_f32; w * h];
    p[0] = 1.0;
    p[3] = 1.0;
    let sig = betti_superlevel_signature(&p, w, h, 0.5, true);
    assert!(sig.beta0 >= 1);
}

#[test]
fn topology_alpha_nonempty() {
    let w = 8_u32;
    let h = 8_u32;
    let mut rgb = vec![0.0_f32; (w * h * 3) as usize];
    for i in 0..(w * h) as usize {
        rgb[i * 3] = 0.2;
        rgb[i * 3 + 1] = 0.5;
        rgb[i * 3 + 2] = 0.8;
    }
    let (alpha, prov) = build_topology_alpha(
        &rgb,
        w,
        h,
        RgbLayout::SequentialRgb,
        &TopologyAlphaConfig::default(),
    )
    .expect("alpha");
    assert_eq!(alpha.len(), (w * h) as usize);
    assert!(!prov.scales.is_empty());
    assert!(alpha.iter().all(|&x| x >= 0.0 && x <= 1.0));

    let js = serde_json::to_string(&prov).unwrap();
    let round: TopologyMaskProvenance = serde_json::from_str(&js).unwrap();
    assert_eq!(round.width, prov.width);
    assert_eq!(round.scales.len(), prov.scales.len());
}
